{
  "name": "CamaroneraPro - Aquaculture Management",
  "description": "An advanced production tracking system for shrimp aquaculture with automated calculations, analytics, and AI-driven insights.",
  "requestFramePermissions": [
    "camera"
  ]
}

export interface PondRecord {
  id: string;
  fechaSiembra: string;
  fechaCosecha?: string;
  alimento: string;
  laboratorio: string;
  estanque: number;
  hectareas: number;
  pesoAnterior: number;
  pesoActual: number;
  incrementoSemanal: number;
  diasCultivo: number;
  porcentajeSobrevivencia: number;
  densidadInicial: number;
  densidadActual: number;
  biomasaHa: number;
  biomasaTotal: number;
  alimentoSemanal: number;
  alimentoAcumulado: number;
  fca: number; // Feed Conversion Ratio
  camM2Inicial: number;
  camM2Actual: number;
}

export type NewPondRecord = Omit<PondRecord, 'id' | 'incrementoSemanal' | 'biomasaHa' | 'biomasaTotal' | 'fca'>;

import { GoogleGenAI } from "@google/genai";
import { PondRecord } from "../types";

export const analyzeProductionData = async (records: PondRecord[]): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    Eres un experto consultor en acuacultura de camarón.
    Analiza los siguientes registros de producción y proporciona:
    1. Un resumen del estado general de la granja.
    2. Identifica los estanques con mejor y peor desempeño (basado en FCA e incremento semanal).
    3. Sugerencias específicas para mejorar la supervivencia o el factor de conversión alimenticia.
    4. Alertas si algún dato parece fuera de los rangos óptimos.

    Datos de los estanques:
    ${JSON.stringify(records, null, 2)}

    Responde en español de forma profesional y concisa.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        thinkingConfig: { thinkingBudget: 2000 }
      }
    });

    return response.text || "No se pudo generar el análisis en este momento.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Error al conectar con la inteligencia artificial. Por favor, revisa tu conexión o intenta más tarde.";
  }
};

import { PondRecord, NewPondRecord } from './types';

export const calculatePondMetrics = (record: NewPondRecord): Omit<PondRecord, 'id'> => {
  const incrementoSemanal = parseFloat((record.pesoActual - record.pesoAnterior).toFixed(2));

  // Biomasa por Ha = (Densidad Actual * Peso Actual) / 1000 (kg/ha)
  const biomasaHa = parseFloat(((record.densidadActual * record.pesoActual) / 1000).toFixed(2));

  // Biomasa Total = Biomasa por Ha * Hectáreas
  const biomasaTotal = parseFloat((biomasaHa * record.hectareas).toFixed(2));

  // FCA = Alimento Acumulado / Biomasa Total (Simplificado para el demo)
  const fca = biomasaTotal > 0 ? parseFloat((record.alimentoAcumulado / biomasaTotal).toFixed(2)) : 0;

  return {
    ...record,
    incrementoSemanal,
    biomasaHa,
    biomasaTotal,
    fca
  };
};

export const formatNumber = (num: number) => {
  return new Intl.NumberFormat('es-MX', { maximumFractionDigits: 2 }).format(num);
};

export const formatDate = (dateStr: string) => {
  return new Date(dateStr).toLocaleDateString('es-MX', {
    day: '2-digit',
    month: 'short',
    year: 'numeric'
  });
};

import React from 'react';
import { PondRecord } from '../types';
import { formatNumber } from '../utils';

interface Props {
  records: PondRecord[];
}

const DashboardStats: React.FC<Props> = ({ records }) => {
  const totalBiomass = records.reduce((sum, r) => sum + r.biomasaTotal, 0);
  const avgFca = records.length > 0 ? records.reduce((sum, r) => sum + r.fca, 0) / records.length : 0;
  const avgIncrement = records.length > 0 ? records.reduce((sum, r) => sum + r.incrementoSemanal, 0) / records.length : 0;
  const avgSurvival = records.length > 0 ? records.reduce((sum, r) => sum + r.porcentajeSobrevivencia, 0) / records.length : 0;

  const stats = [
    { label: 'Biomasa Total', value: `${formatNumber(totalBiomass)} kg`, color: 'text-blue-600', icon: '🦐' },
    { label: 'Promedio FCA', value: formatNumber(avgFca), color: 'text-emerald-600', icon: '🍽️' },
    { label: 'Inc. Semanal Prom.', value: `${formatNumber(avgIncrement)} g`, color: 'text-indigo-600', icon: '📈' },
    { label: 'Supervivencia Prom.', value: `${formatNumber(avgSurvival)}%`, color: 'text-amber-600', icon: '❤️' },
  ];

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4 mb-8">
      {stats.map((stat, i) => (
        <div key={i} className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 flex items-center space-x-4">
          <div className="text-2xl">{stat.icon}</div>
          <div>
            <p className="text-sm font-medium text-slate-500">{stat.label}</p>
            <p className={`text-2xl font-bold ${stat.color}`}>{stat.value}</p>
          </div>
        </div>
      ))}
    </div>
  );
};

export default DashboardStats;

