import React, { useState, useEffect, useMemo } from 'react';
import { PondRecord, NewPondRecord } from './types';
import { INITIAL_DATA } from './constants';
import { calculatePondMetrics } from './utils';
import DashboardStats from './components/DashboardStats';
import PondTable from './components/PondTable';
import PondForm from './components/PondForm';
import AIInsights from './components/AIInsights';
import FilterPanel, { FilterState } from './components/FilterPanel';
import StatisticsTable from './components/StatisticsTable';
import GrowthCurveSection from './components/GrowthCurveSection';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer, 
  Cell 
} from 'recharts';

const App: React.FC = () => {
  const [records, setRecords] = useState<PondRecord[]>([]);
  const [showForm, setShowForm] = useState(false);
  const [filters, setFilters] = useState<FilterState>({
    fechaDesde: '',
    fechaHasta: '',
    alimento: '',
    laboratorio: '',
    estanque: ''
  });

  useEffect(() => {
    // Load initial data
    setRecords(INITIAL_DATA);
  }, []);

  const handleAddRecord = (newRecord: NewPondRecord) => {
    const calculated = calculatePondMetrics(newRecord);
    const recordWithId: PondRecord = {
      ...calculated,
      id: Math.random().toString(36).substr(2, 9)
    };
    setRecords(prev => [recordWithId, ...prev]);
    setShowForm(false);
  };

  const handleDeleteRecord = (id: string) => {
    if (confirm('¿Estás seguro de que deseas eliminar este registro?')) {
      setRecords(prev => prev.filter(r => r.id !== id));
    }
  };

  // Extract unique values for filter dropdowns
  const uniqueAlimentos = useMemo(() => Array.from(new Set(records.map(r => r.alimento))), [records]);
  const uniqueLaboratorios = useMemo(() => Array.from(new Set(records.map(r => r.laboratorio))), [records]);
  const uniqueEstanques = useMemo(() => Array.from(new Set(records.map(r => r.estanque))).sort((a: number, b: number) => a - b), [records]);

  // Apply filters
  const filteredRecords = useMemo(() => {
    return records.filter(record => {
      const matchEstanque = filters.estanque === '' || record.estanque.toString() === filters.estanque;
      const matchAlimento = filters.alimento === '' || record.alimento === filters.alimento;
      const matchLab = filters.laboratorio === '' || record.laboratorio === filters.laboratorio;

      const recordDate = new Date(record.fechaSiembra).getTime();
      const matchDesde = filters.fechaDesde === '' || recordDate >= new Date(filters.fechaDesde).getTime();
      const matchHasta = filters.fechaHasta === '' || recordDate <= new Date(filters.fechaHasta).getTime();

      return matchEstanque && matchAlimento && matchLab && matchDesde && matchHasta;
    });
  }, [records, filters]);

  const chartData = useMemo(() => 
    [...filteredRecords].sort((a: PondRecord, b: PondRecord) => a.estanque - b.estanque),
  [filteredRecords]);

  return (
    <div className="min-h-screen pb-12">
      {/* Navigation */}
      <nav className="bg-white border-b border-slate-200 sticky top-0 z-40">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-16 items-center">
            <div className="flex items-center gap-2">
              <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center text-white font-bold">C</div>
              <span className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-blue-600 to-indigo-600">
                CamaroneraPro
              </span>
            </div>
            <div className="flex items-center gap-4">
              <button 
                onClick={() => setShowForm(true)}
                className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg font-semibold flex items-center gap-2 transition-all"
              >
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4" />
                </svg>
                <span className="hidden sm:inline">Nuevo Muestreo</span>
              </button>
            </div>
          </div>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 mt-8 space-y-8">
        {/* Statistics Header */}
        <DashboardStats records={filteredRecords} />

        {/* Filter Panel */}
        <FilterPanel 
          filters={filters} 
          onFilterChange={setFilters} 
          uniqueAlimentos={uniqueAlimentos}
          uniqueLaboratorios={uniqueLaboratorios}
          uniqueEstanques={uniqueEstanques}
        />

        {/* AI Analysis Section */}
        <AIInsights records={filteredRecords} />

        {/* Growth Curve Comparison Section */}
        <GrowthCurveSection />

        {/* Records Table Section */}
        <div className="space-y-4">
          <div className="flex items-center justify-between">
            <h2 className="text-lg font-bold text-slate-800">Registros Recientes</h2>
            <span className="text-sm text-slate-500">
              {filteredRecords.length === records.length 
                ? `${records.length} estanques registrados` 
                : `Mostrando ${filteredRecords.length} de ${records.length} registros`}
            </span>
          </div>
          <PondTable records={filteredRecords} onDelete={handleDeleteRecord} />
        </div>

        {/* Advanced Statistics Table */}
        <StatisticsTable records={filteredRecords} />

        {/* Charts Row */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {/* Weight Chart */}
          <div className="bg-white p-6 rounded-xl border border-slate-100 shadow-sm flex flex-col h-[320px]">
            <h2 className="text-sm font-bold text-slate-600 mb-4 flex items-center gap-2">
              <span className="text-blue-500">⚖️</span> Peso Actual (g)
            </h2>
            <div className="flex-1 min-h-0">
              {chartData.length > 0 ? (
                <ResponsiveContainer width="100%" height="100%">
                  <BarChart data={chartData}>
                    <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                    <XAxis dataKey="estanque" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 11}} label={{ value: 'Estanque', position: 'insideBottom', offset: -5, fontSize: 10, fill: '#94a3b8' }} />
                    <YAxis axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 11}} />
                    <Tooltip 
                      cursor={{fill: '#f8fafc'}}
                      contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                      formatter={(value) => [`${value}g`, 'Peso']}
                      labelFormatter={(label) => `Estanque ${label}`}
                    />
                    <Bar dataKey="pesoActual" radius={[4, 4, 0, 0]}>
                      {chartData.map((entry, index) => (
                        <Cell key={`cell-${index}`} fill={entry.pesoActual > 6 ? '#2563eb' : '#60a5fa'} />
                      ))}
