              ) : (
                <div className="h-full flex items-center justify-center text-slate-400 text-sm italic">Sin datos para graficar</div>
              )}
            </div>
          </div>

          {/* Weekly Increment Chart */}
          <div className="bg-white p-6 rounded-xl border border-slate-100 shadow-sm flex flex-col h-[320px]">
            <h2 className="text-sm font-bold text-slate-600 mb-4 flex items-center gap-2">
              <span className="text-indigo-500">📈</span> Incremento Semanal (g)
            </h2>
            <div className="flex-1 min-h-0">
              {chartData.length > 0 ? (
                <ResponsiveContainer width="100%" height="100%">
                  <BarChart data={chartData}>
                    <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                    <XAxis dataKey="estanque" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 11}} label={{ value: 'Estanque', position: 'insideBottom', offset: -5, fontSize: 10, fill: '#94a3b8' }} />
                    <YAxis axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 11}} />
                    <Tooltip 
                      cursor={{fill: '#f8fafc'}}
                      contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                      formatter={(value) => [`+${value}g`, 'Incremento']}
                      labelFormatter={(label) => `Estanque ${label}`}
                    />
                    <Bar dataKey="incrementoSemanal" radius={[4, 4, 0, 0]}>
                      {chartData.map((entry, index) => (
                        <Cell key={`cell-inc-${index}`} fill={entry.incrementoSemanal > 1.2 ? '#6366f1' : '#818cf8'} />
                      ))}
                    </Bar>
                  </BarChart>
                </ResponsiveContainer>
              ) : (
                <div className="h-full flex items-center justify-center text-slate-400 text-sm italic">Sin datos para graficar</div>
              )}
            </div>
          </div>

          {/* Survival Comparison Bar Chart */}
          <div className="bg-white p-6 rounded-xl border border-slate-100 shadow-sm flex flex-col h-[320px]">
            <h2 className="text-sm font-bold text-slate-600 mb-4 flex items-center gap-2">
              <span className="text-emerald-500">🛡️</span> Supervivencia (%)
            </h2>
            <div className="flex-1 min-h-0">
              {chartData.length > 0 ? (
                <ResponsiveContainer width="100%" height="100%">
                  <BarChart data={chartData}>
                    <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                    <XAxis dataKey="estanque" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 11}} label={{ value: 'Estanque', position: 'insideBottom', offset: -5, fontSize: 10, fill: '#94a3b8' }} />
                    <YAxis domain={[0, 100]} axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 11}} />
                    <Tooltip 
                      cursor={{fill: '#f8fafc'}}
                      contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                      formatter={(value) => [`${value}%`, 'Supervivencia']}
                      labelFormatter={(label) => `Estanque ${label}`}
                    />
                    <Bar dataKey="porcentajeSobrevivencia" radius={[4, 4, 0, 0]}>
                      {chartData.map((entry, index) => (
                        <Cell key={`cell-surv-${index}`} fill={entry.porcentajeSobrevivencia > 75 ? '#10b981' : entry.porcentajeSobrevivencia > 50 ? '#f59e0b' : '#ef4444'} />
                      ))}
                    </Bar>
                  </BarChart>
                </ResponsiveContainer>
              ) : (
                <div className="h-full flex items-center justify-center text-slate-400 text-sm italic">Sin datos para graficar</div>
              )}
            </div>
          </div>
        </div>
      </main>

      {/* Modal Form */}
      {showForm && (
        <PondForm 
          onAdd={handleAddRecord} 
          onCancel={() => setShowForm(false)} 
        />
      )}

      {/* Footer */}
      <footer className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 mt-12 pt-8 border-t border-slate-200">
        <div className="flex flex-col md:flex-row justify-between items-center gap-4 text-slate-400 text-sm">
          <p>© 2024 CamaroneraPro - Sistema de Gestión Acuícola</p>
          <div className="flex gap-6">
            <a href="#" className="hover:text-blue-600 transition-colors">Soporte</a>
