import { PondRecord, NewPondRecord } from './types';

export const calculatePondMetrics = (record: NewPondRecord): Omit<PondRecord, 'id'> => {
  const incrementoSemanal = parseFloat((record.pesoActual - record.pesoAnterior).toFixed(2));

  // Biomasa Total (kg) = (Densidad Actual [individuos] * Peso Actual [g]) / 1000
  const biomasaTotal = parseFloat(((record.densidadActual * record.pesoActual) / 1000).toFixed(2));

  // Biomasa por Ha (kg/ha) = Biomasa Total / Hectáreas
  const biomasaHa = record.hectareas > 0 ? parseFloat((biomasaTotal / record.hectareas).toFixed(2)) : 0;

  // --- Cálculo de FCA (Factor de Conversión Alimenticia) ---
  // Se usa la fórmula estándar: Alimento Acumulado / Ganancia de Biomasa
  // Ganancia de Biomasa = Biomasa Total - Biomasa Inicial

  // Asumimos un peso inicial de siembra estándar para el cálculo.
  const pesoInicialSiembra = 0.003; // gramos (PL estándar)
  const biomasaInicial = (record.densidadInicial * pesoInicialSiembra) / 1000; // en kg

  const gananciaBiomasa = biomasaTotal - biomasaInicial;

  // FCA = Alimento Acumulado (kg) / Ganancia de Biomasa (kg)
  const fca = gananciaBiomasa > 0 ? parseFloat((record.alimentoAcumulado / gananciaBiomasa).toFixed(2)) : 0;

  return {
    ...record,
    incrementoSemanal,
    biomasaHa,
    biomasaTotal,
    fca
  };
};

