                 <h1 className="text-xl font-bold text-slate-800">
                    {activeView === 'dashboard' && 'Dashboard de Producción'}
                    {activeView === 'growthCurve' && 'Curva de Crecimiento'}
                    {activeView === 'farmEvaluation' && 'Evaluación Técnica de Granja'}
                 </h1>
              </div>
              {activeView !== 'farmEvaluation' && (
                <div className="flex items-center gap-4">
                  <button 
                    onClick={() => fileInputRef.current?.click()}
                    className="bg-white border border-slate-300 hover:bg-slate-50 text-slate-700 px-4 py-2 rounded-lg font-semibold flex items-center gap-2 transition-all"
                  >
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12" />
                    </svg>
                    <span className="hidden sm:inline">Cargar Archivo</span>
                  </button>
                  <button 
                    onClick={() => setShowForm(true)}
                    className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg font-semibold flex items-center gap-2 transition-all"
                  >
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4" />
                    </svg>
                    <span className="hidden sm:inline">Nuevo Muestreo</span>
                  </button>
                </div>
              )}
            </div>
          </div>
        </nav>

        <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 mt-8 space-y-8 w-full">
          {activeView === 'dashboard' && (
            <>
              {/* Statistics Header */}
              <DashboardStats records={filteredRecords} />

              {/* Filter Panel */}
              <FilterPanel 
                filters={filters} 
                onFilterChange={setFilters} 
                uniqueAlimentos={uniqueAlimentos}
                uniqueLaboratorios={uniqueLaboratorios}
                uniqueEstanques={uniqueEstanques}
              />

              {/* Records Table Section */}
              <div className="space-y-4">
                <div className="flex items-center justify-between">
