                          <Bar dataKey="porcentajeSobrevivencia" radius={[4, 4, 0, 0]}>
                            {chartData.map((entry, index) => (
                              <Cell key={`cell-surv-${index}`} fill={entry.porcentajeSobrevivencia > 75 ? '#10b981' : entry.porcentajeSobrevivencia > 50 ? '#f59e0b' : '#ef4444'} />
                            ))}
                          </Bar>
                        </BarChart>
                      </ResponsiveContainer>
                    ) : (
                      <div className="h-full flex items-center justify-center text-slate-400 text-sm italic">Sin datos para graficar</div>
