            <h3 className="font-bold text-slate-700 mb-2">Registros de Muestreo</h3>
             <table className="w-full text-left text-xs">
                 <thead className="bg-slate-50 text-slate-500">
                     <tr>
                        <th className="p-2">Días</th>
                        <th className="p-2">Fecha</th>
