    setSelectedPond(null);
  };

  const handleAddRecord = (newRecord: NewPondRecord) => {
    const calculated = calculatePondMetrics(newRecord);
    const recordWithId: PondRecord = {
      ...calculated,
      id: Math.random().toString(36).substr(2, 9)
    };
    setRecords(prev => [recordWithId, ...prev]);
    setShowForm(false);
  };

  const handleDeleteRecord = (id: string) => {
    if (confirm('¿Estás seguro de que deseas eliminar este registro?')) {
      setRecords(prev => prev.filter(r => r.id !== id));
    }
  };

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const data = e.target?.result;
        const workbook = XLSX.read(data, { type: 'array' });
        const sheetName = workbook.SheetNames[0];
        const worksheet = workbook.Sheets[sheetName];
        const json: any[] = XLSX.utils.sheet_to_json(worksheet);

        const newRecords: PondRecord[] = json.map((row) => {
          const newRecord: NewPondRecord = {
            fechaSiembra: row.fechaSiembra ? new Date((Number(row.fechaSiembra) - (25567 + 2)) * 86400 * 1000).toISOString().split('T')[0] : new Date().toISOString().split('T')[0],
            alimento: String(row.alimento || ''),
            laboratorio: String(row.laboratorio || ''),
            estanque: Number(row.estanque || 0),
            hectareas: Number(row.hectareas || 0),
            pesoAnterior: Number(row.pesoAnterior || 0),
            pesoActual: Number(row.pesoActual || 0),
            diasCultivo: Number(row.diasCultivo || 0),
            porcentajeSobrevivencia: Number(row.porcentajeSobrevivencia || 0),
            densidadInicial: Number(row.densidadInicial || 0),
            densidadActual: Number(row.densidadActual || 0),
            alimentoSemanal: Number(row.alimentoSemanal || 0),
            alimentoAcumulado: Number(row.alimentoAcumulado || 0),
            camM2Inicial: Number(row.camM2Inicial || 0),
            camM2Actual: Number(row.camM2Actual || 0)
          };

          const calculated = calculatePondMetrics(newRecord);
          return { ...calculated, id: Math.random().toString(36).substr(2, 9) };
        });

        setRecords(prev => [...newRecords, ...prev]);
        alert(`${newRecords.length} registros importados correctamente.`);
      } catch (error) {
        console.error("Error parsing file:", error);
        alert("Error al procesar el archivo. Asegúrate de que el formato y las columnas son correctas.");
      }
    };
    reader.readAsArrayBuffer(file);
    event.target.value = '';
  };

  const handleExportPDF = async () => {
    setIsExporting(true);
    const doc = new jsPDF();
    const today = new Date().toLocaleDateString('es-MX');
    let yPos = 22;

    // Title
    doc.setFontSize(20);
    doc.text('Reporte de Producción - CamaroneraPro', 14, yPos);
    doc.setFontSize(11);
    doc.setTextColor(100);
    doc.text(`Generado el: ${today}`, 14, yPos + 8);
    yPos += 20;

    // Dashboard Stats
    const statsEl = document.getElementById('dashboard-stats');
    if (statsEl) {
      const canvas = await html2canvas(statsEl, { backgroundColor: null });
      const imgData = canvas.toDataURL('image/png');
      const imgProps = doc.getImageProperties(imgData);
      const pdfWidth = doc.internal.pageSize.getWidth() - 28;
      const pdfHeight = (imgProps.height * pdfWidth) / imgProps.width;
      doc.addImage(imgData, 'PNG', 14, yPos, pdfWidth, pdfHeight);
      yPos += pdfHeight + 10;
    }

    // Charts
    const chartsEl = document.getElementById('charts-container');
    if (chartsEl) {
      const canvas = await html2canvas(chartsEl, { backgroundColor: null });
      const imgData = canvas.toDataURL('image/png');
      const imgProps = doc.getImageProperties(imgData);
      const pdfWidth = doc.internal.pageSize.getWidth() - 28;
      const pdfHeight = (imgProps.height * pdfWidth) / imgProps.width;
      doc.addImage(imgData, 'PNG', 14, yPos, pdfWidth, pdfHeight);
      // FIX: The original code tried to use `lastAutoTable` before any table was created.
      // The y-position should be incremented by the height of the image that was just added.
      yPos += pdfHeight + 10;
    }

    // Statistics Table
    autoTable(doc, {
      startY: yPos,
      html: '#stats-table',
      didParseCell: function (data) {
        if (data.section === 'head') {
          data.cell.styles.fillColor = '#475569';
        }
      },
    });

    yPos = (doc as any).lastAutoTable.finalY + 10;

    // Pond Records Table
    autoTable(doc, {
      startY: yPos,
      html: '#pond-table',
      didParseCell: function (data) {
        if (data.section === 'head') {
          data.cell.styles.fillColor = '#475569';
        }
      },
    });

    doc.save(`reporte-produccion-${new Date().toISOString().split('T')[0]}.pdf`);
    setIsExporting(false);
  };

  const uniqueAlimentos = useMemo(() => Array.from(new Set(records.map(r => r.alimento))), [records]);
  const uniqueLaboratorios = useMemo(() => Array.from(new Set(records.map(r => r.laboratorio))), [records]);
  const uniqueEstanques = useMemo(() => Array.from(new Set(records.map(r => r.estanque))).sort((a, b) => a - b), [records]);

  const latestRecordsByPond = useMemo(() => {
      const latest = new Map<number, PondRecord>();
      records.forEach(record => {
          if (!latest.has(record.estanque) || record.diasCultivo > latest.get(record.estanque)!.diasCultivo) {
              latest.set(record.estanque, record);
          }
      });
      return Array.from(latest.values());
  }, [records]);

  const filteredRecords = useMemo(() => {
    return latestRecordsByPond.filter(record => {
      const matchEstanque = filters.estanque === '' || record.estanque.toString() === filters.estanque;
      const matchAlimento = filters.alimento === '' || record.alimento === filters.alimento;
      const matchLab = filters.laboratorio === '' || record.laboratorio === filters.laboratorio;
      const recordDate = new Date(record.fechaSiembra).getTime();
      const matchDesde = filters.fechaDesde === '' || recordDate >= new Date(filters.fechaDesde).getTime();
      const matchHasta = filters.fechaHasta === '' || recordDate <= new Date(filters.fechaHasta).getTime();
      return matchEstanque && matchAlimento && matchLab && matchDesde && matchHasta;
    });
  }, [latestRecordsByPond, filters]);

  const chartData = useMemo(() => 
    [...filteredRecords].sort((a, b) => a.estanque - b.estanque),
  [filteredRecords]);

  return (
    <div className="flex min-h-screen">
      <Sidebar 
        activeView={activeView} 
        onNavigate={setActiveView}
        onExportPDF={handleExportPDF}
        isExporting={isExporting}
      />

      <div className="flex-1 flex flex-col w-full">
        <input type="file" ref={fileInputRef} onChange={handleFileUpload} className="hidden" accept=".xlsx, .csv" />
        <nav className="bg-white border-b border-slate-200 sticky top-0 z-40">
          <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
            <div className="flex justify-between h-16 items-center">
              <div className="flex items-center gap-2">
                 <h1 className="text-xl font-bold text-slate-800">
                    {activeView === 'dashboard' && 'Dashboard de Producción'}
                    {activeView === 'growthCurve' && 'Curva de Crecimiento'}
                    {activeView === 'farmEvaluation' && 'Evaluación Técnica de Granja'}
                 </h1>
              </div>
              {activeView === 'dashboard' && (
                <div className="flex items-center gap-4">
                  <button onClick={() => fileInputRef.current?.click()} className="bg-white border border-slate-300 hover:bg-slate-50 text-slate-700 px-4 py-2 rounded-lg font-semibold flex items-center gap-2 transition-all">
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12" /></svg>
                    <span className="hidden sm:inline">Cargar Archivo</span>
                  </button>
                  <button onClick={() => setShowForm(true)} className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg font-semibold flex items-center gap-2 transition-all">
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4" /></svg>
                    <span className="hidden sm:inline">Nuevo Muestreo</span>
                  </button>
                </div>
              )}
            </div>
          </div>
        </nav>

        <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 mt-8 space-y-8 w-full">
          {activeView === 'dashboard' && (
            <>
              <div id="dashboard-stats"><DashboardStats records={filteredRecords} /></div>
              <AIInsights records={filteredRecords} />
              <FilterPanel filters={filters} onFilterChange={setFilters} uniqueAlimentos={uniqueAlimentos} uniqueLaboratorios={uniqueLaboratorios} uniqueEstanques={uniqueEstanques} />

              <div className="space-y-4">
                <div className="flex items-center justify-between">
                  <h2 className="text-lg font-bold text-slate-800">Registros Recientes por Estanque</h2>
                  <span className="text-sm text-slate-500">{filteredRecords.length} de {uniqueEstanques.length} estanques mostrados</span>
                </div>
                <PondTable records={filteredRecords} onDelete={handleDeleteRecord} onSelectPond={handlePondSelect} />
              </div>

              <StatisticsTable records={filteredRecords} />

              <div id="charts-container" className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                <div className="bg-white p-6 rounded-xl border border-slate-100 shadow-sm flex flex-col h-[320px]">
                  <h2 className="text-sm font-bold text-slate-600 mb-4 flex items-center gap-2"><span className="text-blue-500">⚖️</span> Peso Actual (g)</h2>
                  <div className="flex-1 min-h-0">
                    {chartData.length > 0 ? (
                      <ResponsiveContainer width="100%" height="100%"><BarChart data={chartData}><CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" /><XAxis dataKey="estanque" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 11}} label={{ value: 'Estanque', position: 'insideBottom', offset: -5, fontSize: 10, fill: '#94a3b8' }} /><YAxis axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 11}} /><Tooltip cursor={{fill: '#f8fafc'}} contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }} formatter={(value: number) => [`${formatNumber(value)} g`, 'Peso']} labelFormatter={(label) => `Estanque ${label}`} /><Bar dataKey="pesoActual" radius={[4, 4, 0, 0]}>{chartData.map((entry, index) => (<Cell key={`cell-${index}`} fill={entry.pesoActual > 6 ? '#2563eb' : '#60a5fa'} />))}</Bar></BarChart></ResponsiveContainer>
                    ) : <div className="h-full flex items-center justify-center text-slate-400 text-sm italic">Sin datos para graficar</div>}
                  </div>
                </div>
                <div className="bg-white p-6 rounded-xl border border-slate-100 shadow-sm flex flex-col h-[320px]">
                  <h2 className="text-sm font-bold text-slate-600 mb-4 flex items-center gap-2"><span className="text-indigo-500">📈</span> Incremento Semanal (g)</h2>
                  <div className="flex-1 min-h-0">
                    {chartData.length > 0 ? (
                      <ResponsiveContainer width="100%" height="100%"><BarChart data={chartData}><CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" /><XAxis dataKey="estanque" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 11}} label={{ value: 'Estanque', position: 'insideBottom', offset: -5, fontSize: 10, fill: '#94a3b8' }} /><YAxis axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 11}} /><Tooltip cursor={{fill: '#f8fafc'}} contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }} formatter={(value: number) => [`+${formatNumber(value)} g`, 'Incremento']} labelFormatter={(label) => `Estanque ${label}`} /><Bar dataKey="incrementoSemanal" radius={[4, 4, 0, 0]}>{chartData.map((entry, index) => (<Cell key={`cell-inc-${index}`} fill={entry.incrementoSemanal > 1.2 ? '#6366f1' : '#818cf8'} />))}</Bar></BarChart></ResponsiveContainer>
                    ) : <div className="h-full flex items-center justify-center text-slate-400 text-sm italic">Sin datos para graficar</div>}
                  </div>
                </div>
                <div className="bg-white p-6 rounded-xl border border-slate-100 shadow-sm flex flex-col h-[320px]">
                  <h2 className="text-sm font-bold text-slate-600 mb-4 flex items-center gap-2"><span className="text-emerald-500">🛡️</span> Supervivencia (%)</h2>
                  <div className="flex-1 min-h-0">
                    {chartData.length > 0 ? (
                      <ResponsiveContainer width="100%" height="100%"><BarChart data={chartData}><CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" /><XAxis dataKey="estanque" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 11}} label={{ value: 'Estanque', position: 'insideBottom', offset: -5, fontSize: 10, fill: '#94a3b8' }} /><YAxis domain={[0, 100]} axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 11}} /><Tooltip cursor={{fill: '#f8fafc'}} contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }} formatter={(value: number) => [`${formatNumber(value)}%`, 'Supervivencia']} labelFormatter={(label) => `Estanque ${label}`} /><Bar dataKey="porcentajeSobrevivencia" radius={[4, 4, 0, 0]}>{chartData.map((entry, index) => (<Cell key={`cell-surv-${index}`} fill={entry.porcentajeSobrevivencia > 75 ? '#10b981' : entry.porcentajeSobrevivencia > 50 ? '#f59e0b' : '#ef4444'} />))}</Bar></BarChart></ResponsiveContainer>
                    ) : <div className="h-full flex items-center justify-center text-slate-400 text-sm italic">Sin datos para graficar</div>}
                  </div>
                </div>
              </div>
            </>
          )}

          {activeView === 'growthCurve' && (
             <div className="bg-white rounded-xl shadow-sm border border-slate-100"><div className="px-6 py-4 border-b border-slate-200"><h3 className="text-sm font-bold text-slate-700 uppercase tracking-wider flex items-center gap-2"><svg className="w-4 h-4 text-amber-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 12l3-3 3 3 4-4M8 21l4-4 4 4M3 4h18M4 4h16v12a1 1 0 01-1 1H5a1 1 0 01-1-1V4z" /></svg>Curva de Crecimiento: Estándar vs Real (Gramos)</h3></div><GrowthCurve /></div>
          )}

          {activeView === 'farmEvaluation' && <FarmEvaluationForm />}
        </main>

        {showForm && <PondForm onAdd={handleAddRecord} onCancel={() => setShowForm(false)} />}

        {selectedPond && <PondDetailModal pondId={selectedPond} records={records} onClose={handleCloseModal} />}

        <footer className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 mt-12 mb-8 pt-8 border-t border-slate-200">
          <div className="flex flex-col md:flex-row justify-between items-center gap-4 text-slate-400 text-sm">
            <p>© 2024 CamaroneraPro - Sistema de Gestión Acuícola</p>
            <div className="flex gap-6">
              <a href="#" className="hover:text-blue-600 transition-colors">Soporte</a>
              <a href="#" className="hover:text-blue-600 transition-colors">Privacidad</a>
              <a href="#" className="hover:text-blue-600 transition-colors">Documentación</a>
            </div>
          </div>
        </footer>
      </div>
    </div>
  );
};

export default App;

